namespace sv_dae91836618440598cac58b2b5ba17d9.Services;

/// <summary>
/// Holds all wizard data for a single applicant's session.
/// </summary>
public class WizardState
{
    // Step 1 — Personal Info
    public string Name { get; set; } = "";
    public string Email { get; set; } = "";

    // Step 2 — Experience
    public List<JobEntry> Jobs { get; set; } = [];

    // Step 3 — References
    public List<Reference> References { get; set; } = [];

    // Progress tracking
    public HashSet<int> CompletedSteps { get; set; } = [];
    public int CurrentStep { get; set; } = 1;

    public const int TotalSteps = 4;

    public DateTime LastAccessed { get; set; } = DateTime.UtcNow;
}

public class JobEntry
{
    public string Company { get; set; } = "";
    public string Title { get; set; } = "";
    public string Years { get; set; } = "";
}

public class Reference
{
    public string Name { get; set; } = "";
    public string Relationship { get; set; } = "";
    public string Phone { get; set; } = "";
}

using System.Collections.Concurrent;

namespace sv_dae91836618440598cac58b2b5ba17d9.Services;

/// <summary>
/// Singleton store that holds wizard state keyed by session ID.
/// Both static SSR (layout) and interactive pages resolve the same instance.
/// </summary>
public class WizardStateStore : IDisposable
{
    private readonly ConcurrentDictionary<string, WizardState> _states = new();
    private readonly Timer _cleanupTimer;

    public WizardStateStore()
    {
        // Purge abandoned sessions every 30 minutes
        _cleanupTimer = new Timer(_ => Cleanup(), null, TimeSpan.FromMinutes(30), TimeSpan.FromMinutes(30));
    }

    public WizardState GetOrCreate(string sessionId)
    {
        return _states.GetOrAdd(sessionId, _ => new WizardState());
    }

    public void Remove(string sessionId)
    {
        _states.TryRemove(sessionId, out _);
    }

    private void Cleanup()
    {
        var cutoff = DateTime.UtcNow.AddHours(-2);
        foreach (var kvp in _states)
        {
            if (kvp.Value.LastAccessed < cutoff)
            {
                _states.TryRemove(kvp.Key, out _);
            }
        }
    }

    public void Dispose()
    {
        _cleanupTimer.Dispose();
    }
}

