﻿@inherits LayoutComponentBase
@inject sv_dae91836618440598cac58b2b5ba17d9.Services.WizardStateStore Store
@inject IHttpContextAccessor HttpContextAccessor

<div class="page">
    <div class="sidebar">
        <NavMenu />
    </div>

    <main>
        <div class="top-row px-4">
            @if (IsWizardRoute)
            {
                <div class="wizard-progress d-flex align-items-center gap-2 flex-grow-1">
                    @for (int i = 1; i <= WizardState.TotalSteps; i++)
                    {
                        var step = i;
                        var label = step switch
                        {
                            1 => "Personal Info",
                            2 => "Experience",
                            3 => "References",
                            4 => "Review",
                            _ => ""
                        };
                        var css = Wizard!.CompletedSteps.Contains(step) ? "completed"
                                : Wizard.CurrentStep == step ? "active"
                                : "pending";

                        <div class="wizard-step @css">
                            <span class="step-number">@step</span>
                            <span class="step-label d-none d-md-inline">@label</span>
                        </div>
                        @if (step < WizardState.TotalSteps)
                        {
                            <div class="step-connector @(Wizard.CompletedSteps.Contains(step) ? "completed" : "")"></div>
                        }
                    }
                    <span class="ms-auto text-nowrap">Step @Wizard!.CurrentStep of @WizardState.TotalSteps</span>
                </div>
            }
            else
            {
                <a href="https://learn.microsoft.com/aspnet/core/" target="_blank">About</a>
            }
        </div>

        <article class="content px-4">
            @Body
        </article>
    </main>
</div>

<div id="blazor-error-ui" data-nosnippet>
    An unhandled error has occurred.
    <a href="." class="reload">Reload</a>
    <span class="dismiss">🗙</span>
</div>

@code {
    using sv_dae91836618440598cac58b2b5ba17d9.Services;

    private WizardState? Wizard { get; set; }

    private bool IsWizardRoute =>
        HttpContextAccessor.HttpContext?.Request.Path.StartsWithSegments("/apply") == true;

    protected override void OnInitialized()
    {
        if (IsWizardRoute)
        {
            var sessionId = HttpContextAccessor.HttpContext!.Session.Id;
            Wizard = Store.GetOrCreate(sessionId);
            Wizard.LastAccessed = DateTime.UtcNow;
        }
    }
}

