@page "/apply/personal-info"
@rendermode InteractiveServer
@inject sv_dae91836618440598cac58b2b5ba17d9.Services.WizardStateStore Store
@inject IHttpContextAccessor HttpContextAccessor
@inject NavigationManager Nav

<PageTitle>Apply — Personal Info</PageTitle>

<h1>Step 1: Personal Information</h1>

<EditForm Model="Wizard" OnValidSubmit="Next" FormName="personal-info">
    <div class="mb-3">
        <label class="form-label">Full Name</label>
        <InputText class="form-control" @bind-Value="Wizard.Name" />
    </div>
    <div class="mb-3">
        <label class="form-label">Email</label>
        <InputText class="form-control" @bind-Value="Wizard.Email" />
    </div>
    <button type="submit" class="btn btn-primary">Next →</button>
</EditForm>

@code {
    using sv_dae91836618440598cac58b2b5ba17d9.Services;

    private WizardState Wizard { get; set; } = new();
    private string _sessionId = "";

    protected override void OnInitialized()
    {
        _sessionId = HttpContextAccessor.HttpContext!.Session.Id;
        Wizard = Store.GetOrCreate(_sessionId);
        Wizard.CurrentStep = 1;
        Wizard.LastAccessed = DateTime.UtcNow;
    }

    private void Next()
    {
        Wizard.CompletedSteps.Add(1);
        Nav.NavigateTo("/apply/experience");
    }
}

@page "/apply/experience"
@rendermode InteractiveServer
@inject sv_dae91836618440598cac58b2b5ba17d9.Services.WizardStateStore Store
@inject IHttpContextAccessor HttpContextAccessor
@inject NavigationManager Nav

<PageTitle>Apply — Experience</PageTitle>

<h1>Step 2: Work Experience</h1>

@foreach (var job in Wizard.Jobs)
{
    <div class="card mb-3 p-3">
        <div class="mb-2">
            <label class="form-label">Company</label>
            <input class="form-control" @bind="job.Company" />
        </div>
        <div class="mb-2">
            <label class="form-label">Title</label>
            <input class="form-control" @bind="job.Title" />
        </div>
        <div class="mb-2">
            <label class="form-label">Years</label>
            <input class="form-control" @bind="job.Years" />
        </div>
        <button class="btn btn-outline-danger btn-sm" @onclick="() => Wizard.Jobs.Remove(job)">Remove</button>
    </div>
}

<button class="btn btn-outline-secondary mb-3" @onclick="AddJob">+ Add Job</button>

<div class="d-flex gap-2">
    <button class="btn btn-secondary" @onclick="Back">← Back</button>
    <button class="btn btn-primary" @onclick="Next">Next →</button>
</div>

@code {
    using sv_dae91836618440598cac58b2b5ba17d9.Services;

    private WizardState Wizard { get; set; } = new();

    protected override void OnInitialized()
    {
        var sessionId = HttpContextAccessor.HttpContext!.Session.Id;
        Wizard = Store.GetOrCreate(sessionId);
        Wizard.CurrentStep = 2;
        Wizard.LastAccessed = DateTime.UtcNow;
    }

    private void AddJob() => Wizard.Jobs.Add(new JobEntry());

    private void Back() => Nav.NavigateTo("/apply/personal-info");

    private void Next()
    {
        Wizard.CompletedSteps.Add(2);
        Nav.NavigateTo("/apply/references");
    }
}

