@page "/apply/review"
@rendermode InteractiveServer
@inject sv_dae91836618440598cac58b2b5ba17d9.Services.WizardStateStore Store
@inject IHttpContextAccessor HttpContextAccessor
@inject NavigationManager Nav

<PageTitle>Apply — Review</PageTitle>

<h1>Step 4: Review Your Application</h1>

<div class="card mb-3 p-3">
    <h5>Personal Information</h5>
    <p><strong>Name:</strong> @Wizard.Name</p>
    <p><strong>Email:</strong> @Wizard.Email</p>
</div>

<div class="card mb-3 p-3">
    <h5>Work Experience</h5>
    @if (Wizard.Jobs.Count == 0)
    {
        <p class="text-muted">No jobs added.</p>
    }
    @foreach (var job in Wizard.Jobs)
    {
        <p>@job.Title at @job.Company (@job.Years years)</p>
    }
</div>

<div class="card mb-3 p-3">
    <h5>References</h5>
    @if (Wizard.References.Count == 0)
    {
        <p class="text-muted">No references added.</p>
    }
    @foreach (var r in Wizard.References)
    {
        <p>@r.Name — @r.Relationship (@r.Phone)</p>
    }
</div>

<div class="d-flex gap-2">
    <button class="btn btn-secondary" @onclick="Back">← Back</button>
    <button class="btn btn-success" @onclick="Submit">Submit Application</button>
</div>

@code {
    using sv_dae91836618440598cac58b2b5ba17d9.Services;

    private WizardState Wizard { get; set; } = new();
    private string _sessionId = "";

    protected override void OnInitialized()
    {
        _sessionId = HttpContextAccessor.HttpContext!.Session.Id;
        Wizard = Store.GetOrCreate(_sessionId);
        Wizard.CurrentStep = 4;
        Wizard.CompletedSteps.Add(4);
        Wizard.LastAccessed = DateTime.UtcNow;
    }

    private void Back() => Nav.NavigateTo("/apply/references");

    private void Submit()
    {
        // Persist to database here, then clean up session state.
        Store.Remove(_sessionId);
        Nav.NavigateTo("/");
    }
}

